+// Define a custom DataSource for LazyForEach
+class CustomLottieDataSource implements IDataSource {
+  private dataArray: string[] = [];
+  private listeners: IDataSourceObserver[] = [];
+
+  constructor(data: string[]) {
+    this.dataArray = data;
+  }
+
+  totalCount(): number {
+    return this.dataArray.length;
+  }
+
+  getData(index: number): string {
+    return this.dataArray[index];
+  }
+
+  registerDataChangeListener(listener: IDataSourceObserver): void {
+    if (this.listeners.indexOf(listener) < 0) {
+      this.listeners.push(listener);
+    }
+  }
+
+  unregisterDataChangeListener(listener: IDataSourceObserver): void {
+    const index = this.listeners.indexOf(listener);
+    if (index >= 0) {
+      this.listeners.splice(index, 1);
+    }
+  }
+}

